import React, { useMemo } from 'react'
import { useCurrentFrame, useVideoConfig, interpolate } from 'remotion'

export const AnimationComponent = () => {
  const frame = useCurrentFrame()
  const { width, height, durationInFrames } = useVideoConfig()

  const title = "IMF Emergency Reserve Distribution (2021)"
  const rawLineValues = ["50B", "100B", "200B", "300B", "650B"]
  const rawXLabels = ["Q1", "Q2", "Q3", "Q4", "Total"]

  // Filter data early
  const data = useMemo(() => {
    const filled = rawLineValues
      .map((val, i) => ({ val, label: rawXLabels[i] }))
      .filter(item => item.val !== '' && item.val !== 'Placeholder' && !item.val.startsWith('LINE_VALUE_'))
    return filled.length > 0 ? filled : [
      { val: '$2.1M', label: '2021' },
      { val: '$3.5M', label: '2022' },
      { val: '$4.2M', label: '2023' },
      { val: '$5.8M', label: '2024' },
      { val: '$7.4M', label: '2025' }
    ]
  }, [])

  const lineValues = data.map(d => d.val)
  const xLabels = data.map(d => d.label)
  const itemCount = data.length

  // Entrance
  const entryOp = interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  const gridOp = interpolate(frame, [15, 35], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
  
  // Line Animation configuration
  const lineStart = 40
  const lineEnd = durationInFrames - 60
  const lineProgress = interpolate(frame, [lineStart, lineEnd], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })

  // Chart area dimensions
  const chartLeft = 300
  const chartRight = 1620
  const chartTop = 250
  const chartBottom = 800
  const chartW = chartRight - chartLeft
  const chartH = chartBottom - chartTop

  // Normalized points (relative to chart area)
  const points = useMemo(() => {
    // Default Y ratios if no numeric data is easily parseable
    const yRatios = [0.8, 0.6, 0.5, 0.3, 0.1]
    return Array.from({ length: itemCount }).map((_, i) => ({
      x: chartLeft + (itemCount > 1 ? (chartW / (itemCount - 1)) * i : 0),
      y: chartBottom - (yRatios[i % yRatios.length] * chartH)
    }))
  }, [itemCount, chartLeft, chartW, chartBottom, chartH])

  // Calculate visible polyline path based on progress
  const progressInSegments = lineProgress * (points.length - 1)
  const fullSegmentsDone = Math.floor(progressInSegments)
  const partialProgress = progressInSegments - fullSegmentsDone

  const visiblePoints: { x: number; y: number }[] = []
  for (let i = 0; i <= fullSegmentsDone && i < points.length; i++) {
    visiblePoints.push(points[i])
  }
  if (fullSegmentsDone < points.length - 1) {
    const from = points[fullSegmentsDone]
    const to = points[fullSegmentsDone + 1]
    visiblePoints.push({
      x: from.x + (to.x - from.x) * partialProgress,
      y: from.y + (to.y - from.y) * partialProgress,
    })
  }

  const polylinePath = visiblePoints.map(p => `${p.x},${p.y}`).join(' ')
  const areaPath = visiblePoints.length > 0 
    ? `${polylinePath} ${visiblePoints[visiblePoints.length - 1].x},${chartBottom} ${visiblePoints[0].x},${chartBottom}`
    : ''

  const currentX = visiblePoints.length > 0 ? visiblePoints[visiblePoints.length - 1].x : chartLeft
  const currentY = visiblePoints.length > 0 ? visiblePoints[visiblePoints.length - 1].y : chartBottom

  return (
    <div style={{
      position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden',
      backgroundColor: '#F2F2F0', fontFamily: 'Inter, system-ui, sans-serif'
    }}>
      {/* Background Decor */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px)',
        backgroundSize: '100px 100px',
        opacity: 0.5
      }} />

      {/* Header */}
      <div style={{ position: 'absolute', top: 80, left: 80, opacity: entryOp }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
          <div style={{ width: 12, height: 48, backgroundColor: '#0D1B2A', borderRadius: 4, boxShadow: '0 0 20px #0D1B2A' }} />
          <div style={{ 
            fontSize: 48, fontWeight: 900, color: '#fff', letterSpacing: '0.1em', 
            textTransform: 'uppercase', textShadow: '0 2px 20px rgba(0,0,0,0.8)' 
          }}>
            {title}
          </div>
        </div>
        <div style={{ 
          fontSize: 24, color: '#888888', marginLeft: 36, marginTop: 4, 
          fontWeight: 600, letterSpacing: '0.05em', textShadow: '0 1px 10px rgba(0,0,0,0.3)' 
        }}>
          ANALYTIC_STREAM_v4.0
        </div>
      </div>

      <svg width={1920} height={1080} style={{ position: 'absolute', top: 0, left: 0, zIndex: 1 }}>
        {/* Horizontal Grid Lines */}
        {[0, 0.25, 0.5, 0.75, 1].map((r, i) => (
          <line
            key={i}
            x1={chartLeft} y1={chartBottom - r * chartH}
            x2={chartRight} y2={chartBottom - r * chartH}
            stroke="rgba(255,255,255,0.05)" strokeWidth={2}
            opacity={gridOp}
          />
        ))}

        {/* Vertical Axis */}
        <line x1={chartLeft} y1={chartTop} x2={chartLeft} y2={chartBottom} stroke="#0D1B2A" strokeWidth={4} opacity={gridOp} />
        <line x1={chartLeft} y1={chartBottom} x2={chartRight} y2={chartBottom} stroke="#0D1B2A" strokeWidth={4} opacity={gridOp} />

        {/* Gradient Area Fill */}
        <defs>
          <linearGradient id="areaGrad" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor="#0D1B2A" stopOpacity="0.3" />
            <stop offset="100%" stopColor="#0D1B2A" stopOpacity="0" />
          </linearGradient>
        </defs>
        {visiblePoints.length > 1 && (
          <polygon points={areaPath} fill="url(#areaGrad)" opacity={0.6} />
        )}

        {/* The Main Line */}
        {visiblePoints.length > 1 && (
          <polyline
            points={polylinePath}
            fill="none"
            stroke="#0D1B2A"
            strokeWidth={8}
            strokeLinejoin="round"
            strokeLinecap="round"
            style={{ filter: 'drop-shadow(0 0 15px #0D1B2A)' }}
          />
        )}

        {/* Leading Edge Comet */}
        {lineProgress > 0 && lineProgress < 1 && (
          <circle cx={currentX} cy={currentY} r={12} fill="#fff" style={{ filter: 'drop-shadow(0 0 20px #fff)' }} />
        )}

        {/* Data Points */}
        {points.map((p, i) => {
          const reachFrame = lineStart + (i * (lineEnd - lineStart) / (itemCount - 1))
          const pop = interpolate(frame, [reachFrame, reachFrame + 10], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
          return (
            <g key={`dot-${i}`} opacity={pop}>
              <circle cx={p.x} cy={p.y} r={14} fill="#F2F2F0" stroke="#0D1B2A" strokeWidth={4} />
              <circle cx={p.x} cy={p.y} r={6} fill="#FFCC00" />
            </g>
          )
        })}
      </svg>

      {/* Axis Labels */}
      {points.map((p, i) => {
        const reachFrame = lineStart + (i * (lineEnd - lineStart) / (itemCount - 1))
        const op = interpolate(frame, [reachFrame + 5, reachFrame + 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
        return (
          <div key={`label-${i}`} style={{
            position: 'absolute', top: chartBottom + 24, left: p.x, transform: 'translateX(-50%)',
            opacity: op, color: 'rgba(255,255,255,0.4)', fontSize: 20, fontWeight: 700, fontFamily: 'monospace'
          }}>
            {xLabels[i]}
          </div>
        )
      })}

      {/* Data Callouts (Modern UI Style) */}
      {points.map((p, i) => {
        const reachFrame = lineStart + (i * (lineEnd - lineStart) / (itemCount - 1))
        const op = interpolate(frame, [reachFrame + 10, reachFrame + 25], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
        const ty = interpolate(frame, [reachFrame + 10, reachFrame + 25], [20, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
        
        return (
          <div key={`callout-${i}`} style={{
            position: 'absolute', top: p.y - 100, left: p.x, transform: `translateX(-50%) translateY(${ty}px)`,
            opacity: op, backgroundColor: 'rgba(15, 23, 42, 0.9)', backdropFilter: 'blur(12px)',
            borderRadius: 12, border: '1px solid rgba(255,255,255,0.2)', padding: '12px 20px',
            boxShadow: '0 10px 30px rgba(0,0,0,0.5)', zIndex: 10, minWidth: 120, textAlign: 'center'
          }}>
            <div style={{ color: '#FFCC00', fontSize: 28, fontWeight: 900, letterSpacing: '-0.02em' }}>
              {lineValues[i]}
            </div>
          </div>
        )
      })}

      {/* Footer System Status */}
      <div style={{ position: 'absolute', bottom: 60, right: 80, opacity: entryOp, textAlign: 'right' }}>
        <div style={{ color: 'rgba(255,255,255,0.2)', fontSize: 16, fontFamily: 'monospace' }}>
          DATA_INTEGRITY: 100%<br />
          SOURCE_FEED: TR-742-ALPHA
        </div>
      </div>
    </div>
  )
}

export default AnimationComponent

import React, { useMemo } from 'react';
import { useCurrentFrame, useVideoConfig, interpolate, Easing } from 'remotion';

export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height, durationInFrames } = useVideoConfig();

  const steps = useMemo(() => [
    { title: 'The Symptom', body: 'Unequal reserve distribution.' },
    { title: 'The Mechanism', body: 'Structural financial rules.' },
    { title: 'The History', body: 'Post-WWII institutional design.' },
    { title: 'The Impact', body: 'Systemic economic asymmetry.' }
  ].filter(s => s.title !== '' && s.title !== ' ' && !s.title.includes('STEP_TITLE')), [
    'The Symptom', 'Unequal reserve distribution.', 'The Mechanism', 'Structural financial rules.', 
    'The History', 'Post-WWII institutional design.', 'The Impact', 'Systemic economic asymmetry.'
  ]);

  // If filtered out by placeholder logic but we want to show something during dev
  const activeSteps = steps.length > 0 ? steps : [
      { title: 'STRATEGIC_PLANNING', body: 'Initial phase involving stakeholder alignment and objective definition.' },
      { title: 'DATA_ACQUISITION', body: 'Harvesting raw intelligence from distributed network nodes.' },
      { title: 'ALGORITHMIC_ANALYSIS', body: 'Processing datasets through proprietary neural pathways.' },
      { title: 'OPERATIONAL_DEPLOYMENT', body: 'Final execution of verified strategic protocols.' }
  ];

  const glassStyle: React.CSSProperties = {
    backgroundColor: 'rgba(15, 23, 42, 0.8)',
    backdropFilter: 'blur(20px)',
    border: '1px solid rgba(255, 255, 255, 0.1)',
    borderRadius: '24px',
    padding: '40px',
    boxShadow: '0 20px 50px rgba(0,0,0,0.4)',
    position: 'relative',
    transition: 'all 0.3s ease-out'
  }

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#F2F2F0', fontFamily: 'Inter, system-ui, sans-serif' }}>

      {/* Background Decor */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.02) 0%, transparent 80%), linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px)',
        backgroundSize: '100% 100%, 80px 80px, 80px 80px',
        opacity: 0.5
      }} />

      {/* Header UI */}
      <div style={{ position: 'absolute', top: 60, left: 100, zIndex: 10 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
            <div style={{ width: 8, height: 40, backgroundColor: '#0D1B2A', borderRadius: 4, boxShadow: '0 0 15px #0D1B2A' }} />
            <div style={{ fontSize: 32, fontWeight: 900, color: '#fff', letterSpacing: '0.1em', textTransform: 'uppercase' }}>PROCESS_WORKFLOW</div>
        </div>
      </div>

      {/* Vertical Timeline Thread */}
      <div style={{ position: 'absolute', top: 180, bottom: 80, left: 140, width: 2, backgroundColor: 'rgba(255,255,255,0.1)', zIndex: 1 }} />

      {/* Steps Container */}
      <div style={{ position: 'absolute', top: 180, left: 100, right: 100, bottom: 80, display: 'flex', flexDirection: 'column', gap: 20, zIndex: 5 }}>
        {activeSteps.map((step, i) => {
            const stepStart = 10 + (i * 45);

            // Entrance
            const op = interpolate(frame, [stepStart, stepStart + 25], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
            const tx = interpolate(frame, [stepStart, stepStart + 25], [50, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp', easing: Easing.out(Easing.quad) });

            // Activity State (High-lighting current)
            const isLast = i === activeSteps.length - 1;
            const nextStart = stepStart + 45;
            const isActive = frame >= stepStart && (isLast ? true : frame < nextStart);
            const isPast = frame >= nextStart && !isLast;

            return (
                <div key={i} style={{ 
                    display: 'flex', 
                    gap: 40, 
                    opacity: op, 
                    transform: `translateX(${tx}px)`,
                    filter: `grayscale(${isPast ? 0.8 : 0})`,
                    minHeight: 180 // Ensure consistent row height
                }}>
                    {/* Number Circle */}
                    <div style={{ 
                        width: 80, height: 80, borderRadius: '50%', 
                        backgroundColor: isActive ? '#0D1B2A' : 'rgba(255,255,255,0.05)',
                        border: `2px solid ${isActive ? '#FFCC00' : 'rgba(255,255,255,0.1)'}`,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 32, fontWeight: 900, color: isActive ? '#000' : 'rgba(255,255,255,0.3)',
                        boxShadow: isActive ? '0 0 30px #0D1B2A' : 'none',
                        flexShrink: 0, zIndex: 10,
                        transition: 'all 0.3s ease-out',
                        marginTop: 10
                    }}>
                        {i + 1}
                    </div>

                    {/* Content Card */}
                    <div style={{ 
                        ...glassStyle, 
                        flex: 1, 
                        borderLeft: `8px solid ${isActive ? '#0D1B2A' : 'rgba(255,255,255,0.1)'}`,
                        opacity: isPast ? 0.5 : 1,
                        transform: isActive ? 'scale(1.01)' : 'scale(1)',
                        padding: '30px 40px'
                    }}>
                        <div style={{ position: 'absolute', top: 20, right: 30, color: 'rgba(255,255,255,0.05)', fontFamily: 'monospace', fontSize: 14 }}>NODE_REF: 0x0{i+1}</div>
                        <div style={{ fontSize: 14, color: '#FFCC00', fontWeight: 900, letterSpacing: '0.3em', textTransform: 'uppercase', marginBottom: 8 }}>{step.title}</div>
                        <div style={{ fontSize: 24, fontWeight: 800, color: '#fff', letterSpacing: '0.02em', marginBottom: 12 }}>{step.title}</div>
                        <div style={{ fontSize: 20, color: 'rgba(255,255,255,0.7)', lineHeight: 1.5, fontWeight: 400 }}>{step.body}</div>
                    </div>
                </div>
            );
        })}
      </div>

      {/* Forensic Detail */}
      <div style={{ position: 'absolute', bottom: 40, right: 60, opacity: 0.2, textAlign: 'right' }}>
         <div style={{ color: '#fff', fontSize: 12, fontFamily: 'monospace' }}>
            NARRATIVE_FLOW: ACTIVE<br />
            STEPS_MAPPED: {activeSteps.length}<br />
            STATUS: REALTIME_UPDATE
         </div>
      </div>

    </div>
  );
};

export default AnimationComponent;

import React, { useMemo } from 'react'
import { useCurrentFrame, useVideoConfig, interpolate, Easing } from 'remotion'

export const AnimationComponent = () => {
  const frame = useCurrentFrame()
  const { width, height } = useVideoConfig()

  const title = "Crisis Response Capacity"
  const compareLabel1 = "Nairobi / Lusaka"
  const compareLabel2 = "Washington / Frankfurt"
  const compareValue1 = "Limited Liquidity"
  const compareValue2 = "Unlimited Reserve Access"
  const contextText = "Structural Asymmetry"

  const items = useMemo(() => {
    const rawItems = [
      { label: compareLabel1, value: compareValue1, color: '#0D1B2A', accent: '#FFCC00' },
      { label: compareLabel2, value: compareValue2, color: '#FF2222', accent: '#888888' }
    ]
    return rawItems.filter(item => item.label !== '' && item.label !== 'Placeholder' && item.value !== '' && item.value !== 'Placeholder')
  }, [compareLabel1, compareLabel2, compareValue1, compareValue2])

  // Animation Timings
  const entranceStart = 10
  const bgOp = interpolate(frame, [0, 20], [0, 1], { extrapolateRight: 'clamp' })
  const titleOp = interpolate(frame, [entranceStart, entranceStart + 30], [0, 1], { extrapolateRight: 'clamp' })
  const titleTy = interpolate(frame, [entranceStart, entranceStart + 30], [20, 0], { extrapolateRight: 'clamp', easing: Easing.out(Easing.quad) })
  
  const col1Op = interpolate(frame, [entranceStart + 20, entranceStart + 50], [0, 1], { extrapolateRight: 'clamp' })
  const col1Scale = interpolate(frame, [entranceStart + 20, entranceStart + 55], [0.95, 1], { extrapolateRight: 'clamp', easing: Easing.out(Easing.quad) })
  
  const vsOp = interpolate(frame, [entranceStart + 40, entranceStart + 60], [0, 1], { extrapolateRight: 'clamp' })
  const vsScale = interpolate(frame, [entranceStart + 40, entranceStart + 65], [0.5, 1], { extrapolateRight: 'clamp', easing: Easing.out(Easing.back(1.5)) })

  const col2Op = interpolate(frame, [entranceStart + 30, entranceStart + 60], [0, 1], { extrapolateRight: 'clamp' })
  const col2Scale = interpolate(frame, [entranceStart + 30, entranceStart + 65], [0.95, 1], { extrapolateRight: 'clamp', easing: Easing.out(Easing.quad) })

  const glassStyle: React.CSSProperties = {
    backgroundColor: 'rgba(15, 23, 42, 0.92)',
    backdropFilter: 'blur(32px)',
    border: '1px solid rgba(255, 255, 255, 0.15)',
    borderRadius: '32px',
    boxShadow: '0 40px 100px rgba(0,0,0,0.6)',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '60px',
    width: 600,
    height: 500,
    position: 'relative',
    overflow: 'hidden'
  }

  // Dynamic Font Scaling for Comparison Values
  const getFontSize = (val: string) => {
    const len = String(val).length;
    if (len <= 4) return 120;
    if (len <= 6) return 100;
    if (len <= 10) return 80;
    return 60;
  };

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#F2F2F0', fontFamily: 'Inter, system-ui, sans-serif' }}>
      
      {/* Cinematic Background Grid */}
      <div style={{
        position: 'absolute', width: '100%', height: '100%',
        backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.02) 0%, transparent 80%), linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px)',
        backgroundSize: '100% 100%, 100px 100px, 100px 100px',
        opacity: bgOp * 0.6
      }} />

      {/* Header UI */}
      <div style={{ position: 'absolute', top: 80, width: '100%', textAlign: 'center', opacity: titleOp, transform: `translateY(${titleTy}px)`, zIndex: 10 }}>
        <div style={{ fontSize: 16, fontWeight: 900, color: '#FFCC00', letterSpacing: '0.6em', textTransform: 'uppercase', textShadow: '0 2px 10px rgba(0,0,0,0.5)' }}>DIFFERENTIAL_ANALYSIS_v9.2</div>
        <div style={{ fontSize: 56, fontWeight: 900, color: '#fff', letterSpacing: '0.05em', textTransform: 'uppercase', textShadow: '0 2px 20px rgba(0,0,0,0.8)' }}>{title}</div>
        <div style={{ width: 120, height: 4, backgroundColor: '#0D1B2A', margin: '20px auto', borderRadius: 2, boxShadow: '0 0 20px #0D1B2A' }} />
      </div>

      {/* Comparison Container */}
      <div style={{
        position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -40%)',
        display: 'flex', alignItems: 'center', gap: 60, zIndex: 5
      }}>
        
        {/* Left Side */}
        {items[0] && (
            <div style={{ ...glassStyle, opacity: col1Op, transform: `scale(${col1Scale})`, borderTop: `8px solid ${items[0].color}` }}>
                <div style={{ position: 'absolute', top: 0, right: 0, width: 300, height: 300, background: `radial-gradient(circle, ${items[0].color} 0%, transparent 70%)`, opacity: 0.1 }} />
                <div style={{ fontSize: 18, color: 'rgba(255,255,255,0.7)', fontWeight: 900, letterSpacing: '0.2em', textTransform: 'uppercase', marginBottom: 20, textAlign: 'center' }}>{items[0].label}</div>
                <div style={{ 
                    fontSize: getFontSize(items[0].value), 
                    fontWeight: 900, 
                    color: '#FFFFFF', 
                    fontFamily: 'monospace', 
                    lineHeight: 1, 
                    textAlign: 'center',
                    textShadow: `0 0 40px ${items[0].color}44`,
                    wordBreak: 'break-all'
                }}>{items[0].value}</div>
                <div style={{ marginTop: 40, width: 60, height: 2, backgroundColor: 'rgba(255,255,255,0.1)' }} />
            </div>
        )}

        {/* VS Element */}
        <div style={{ 
            width: 100, height: 100, borderRadius: '50%', backgroundColor: 'rgba(15, 23, 42, 0.95)',
            border: '2px solid rgba(255,255,255,0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center',
            opacity: vsOp, transform: `scale(${vsScale})`, zIndex: 10, backdropFilter: 'blur(10px)',
            boxShadow: '0 10px 30px rgba(0,0,0,0.5)'
        }}>
            <div style={{ fontSize: 28, fontWeight: 900, color: '#FFCC00', letterSpacing: '0.1em' }}>VS</div>
        </div>

        {/* Right Side */}
        {items[1] && (
            <div style={{ ...glassStyle, opacity: col2Op, transform: `scale(${col2Scale})`, borderTop: `8px solid ${items[1].color}` }}>
                <div style={{ position: 'absolute', top: 0, right: 0, width: 300, height: 300, background: `radial-gradient(circle, ${items[1].color} 0%, transparent 70%)`, opacity: 0.1 }} />
                <div style={{ fontSize: 18, color: 'rgba(255,255,255,0.7)', fontWeight: 900, letterSpacing: '0.2em', textTransform: 'uppercase', marginBottom: 20, textAlign: 'center' }}>{items[1].label}</div>
                <div style={{ 
                    fontSize: getFontSize(items[1].value), 
                    fontWeight: 900, 
                    color: items[1].color, 
                    fontFamily: 'monospace', 
                    lineHeight: 1, 
                    textAlign: 'center',
                    textShadow: `0 0 40px ${items[1].color}44`,
                    wordBreak: 'break-all'
                }}>{items[1].value}</div>
                <div style={{ marginTop: 40, width: 60, height: 2, backgroundColor: 'rgba(255,255,255,0.1)' }} />
            </div>
        )}

      </div>

      {/* Context Text Footer */}
      <div style={{ 
          position: 'absolute', bottom: 100, width: '100%', textAlign: 'center', 
          opacity: col2Op, transform: `translateY(${interpolate(frame, [entranceStart + 40, entranceStart + 70], [20, 0], { extrapolateRight: 'clamp' })}px)` 
      }}>
        <div style={{ maxWidth: 1000, margin: '0 auto', fontSize: 24, color: '#fff', lineHeight: 1.6, fontWeight: 500, textShadow: '0 2px 10px rgba(0,0,0,0.8)' }}>
            {contextText}
        </div>
      </div>

      {/* Decorative Side Elements */}
      <div style={{ position: 'absolute', bottom: 60, left: 80, opacity: 0.3 }}>
        <div style={{ color: '#fff', fontSize: 12, fontFamily: 'monospace', textShadow: '0 1px 4px rgba(0,0,0,0.5)' }}>
            COORD_SYNC: STABLE // MODE: CROSS_REF<br />
