        </div>
        <div style={{ fontSize: 14, color: '#FFCC00', fontWeight: 800, letterSpacing: '0.4em', textTransform: 'uppercase', marginTop: 10, marginLeft: 26 }}>GLOBAL_OPERATIONS_MAP_v2.4</div>
      </div>

      <svg width={1920} height={1080} style={{ position: 'absolute', top: 0, left: 0 }}>
        <defs>
          <linearGradient id="arcGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#0D1B2A" stopOpacity="0" />
            <stop offset="50%" stopColor="#FFCC00" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#FF2222" stopOpacity="0" />
          </linearGradient>
          <filter id="glow">
            <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
            <feMerge>
              <feMergeNode in="coloredBlur"/>
              <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
        </defs>

        {/* Connection Arcs */}
        {filteredData.map((item, i) => {
          const path = getArcPath(source, item.target)
          return (
            <g key={`arc-${i}`}>
              {/* Static Background Arc */}
              <path 
                d={path} 
                fill="none" 
                stroke="#0D1B2A" 
                strokeWidth={2} 
                opacity={mapOp * 0.15} 
                strokeDasharray="4 4" 
              />
              
              {/* Animated Reveal Arc */}
              <path 
                d={path} 
                fill="none" 
                stroke="#FFCC00" 
                strokeWidth={3} 
                strokeDasharray="1000"
                strokeDashoffset={1000 * (1 - arcProgress)}
                opacity={0.8}
                filter="url(#glow)"
              />

              {/* Data Flow Particle */}
              <circle r={4} fill="#fff" filter="url(#glow)">
                <animateMotion 
                  path={path} 
                  dur={`${2 + i * 0.5}s`} 
                  repeatCount="indefinite" 
                  begin={`${i * 0.3}s`}
                />
              </circle>
            </g>
          )
        })}

        {/* Source Node */}
        <g opacity={mapOp}>
          <circle cx={source.x} cy={source.y} r={24} fill="rgba(15, 23, 42, 0.9)" stroke="#0D1B2A" strokeWidth={2} />
          <circle cx={source.x} cy={source.y} r={8} fill="#0D1B2A" filter="url(#glow)">
            <animate attributeName="r" values="6;10;6" dur="2s" repeatCount="indefinite" />
          </circle>
        </g>

        {/* Target Dots */}
        {filteredData.map((item, i) => (
          <g key={`dot-${i}`} opacity={labelOp}>
            <circle cx={item.target.x} cy={item.target.y} r={18} fill="none" stroke="#FFCC00" strokeWidth={1} opacity={0.3}>
                <animate attributeName="r" values="18;28;18" dur="3s" repeatCount="indefinite" />
            </circle>
            <circle cx={item.target.x} cy={item.target.y} r={6} fill="#FFCC00" filter="url(#glow)" />
          </g>
        ))}
      </svg>

      {/* Source Label (Glass) */}
      <div style={{ 
        position: 'absolute', top: source.y - 80, left: source.x - 100, 
        width: 200, padding: '10px', backgroundColor: 'rgba(15, 23, 42, 0.9)', 
        backdropFilter: 'blur(12px)', border: '1px solid #0D1B2A', 
        borderRadius: 8, opacity: mapOp, textAlign: 'center'
      }}>
        <div style={{ fontSize: 10, color: '#0D1B2A', fontWeight: 900, letterSpacing: '0.2em', marginBottom: 4 }}>ORIGIN_NODE</div>
        <div style={{ fontSize: 16, fontWeight: 700, color: '#fff', textTransform: 'uppercase' }}>{arcFrom}</div>
      </div>

      {/* Target Labels */}
      {filteredData.map((item, i) => (
        <div key={`label-${i}`} style={{ 
            position: 'absolute', top: item.target.y + 30, left: item.target.x - 100, 
            width: 200, opacity: labelOp, textAlign: 'center' 
        }}>
          <div style={{ fontSize: 18, fontWeight: 800, color: '#fff', textTransform: 'uppercase', letterSpacing: '0.05em', textShadow: '0 2px 10px rgba(0,0,0,0.5)' }}>{item.label}</div>
          <div style={{ height: 2, width: 40, backgroundColor: '#FFCC00', margin: '8px auto', opacity: 0.6 }} />
        </div>
      ))}

      {/* Bottom Forensic Detail */}
      <div style={{ position: 'absolute', bottom: 40, right: 60, opacity: 0.2, textAlign: 'right' }}>
         <div style={{ color: '#fff', fontSize: 12, fontFamily: 'monospace' }}>
            COORD_MAPPING: ENABLED<br />
            ACTIVE_CONNECTIONS: {filteredData.length}<br />
            STATUS: SECURE_RELAY_OK
         </div>
      </div>
    </div>
  )
}

